import React, { useState } from 'react';

const App = () => {
  const [tokens, setTokens] = useState(100);
  const [layers, setLayers] = useState(5);
  const [connections, setConnections] = useState(10);

  const handleTokensChange = (e) => {
    setTokens(parseInt(e.target.value));
  };

  const handleLayersChange = (e) => {
    setLayers(parseInt(e.target.value));
  };

  const handleConnectionsChange = (e) => {
    setConnections(parseInt(e.target.value));
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-80 bg-white p-4 shadow-md rounded-md">
        <div className="flex flex-row items-center justify-between mb-4">
          <h2 className="text-lg font-bold text-gray-800">Model Hierarchy Configuration</h2>
          <button className="bg-orange-500 hover:bg-orange-700 text-white font-bold py-2 px-4 rounded">
            Apply Changes
          </button>
        </div>

        <div className="flex flex-row items-center mb-4">
          <label className="text-gray-700 text-sm">Tokens:</label>
          <input type="number" value={tokens} onChange={handleTokensChange} className="w-20 bg-gray-200 appearance-none border-2 border-gray-200 rounded py-2 px-4 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"/>
        </div>

        <div className="flex flex-row items-center mb-4">
          <label className="text-gray-700 text-sm">Layers:</label>
          <select value={layers} onChange={handleLayersChange} className="w-20 bg-gray-200 appearance-none border-2 border-gray-200 rounded py-2 px-4 text-gray-700 leading-tight focus:outline-none focus:shadow-outline">
            <option value="1">1</option>
            <option value="2">2</option>
            <option value="3">3</option>
            <option value="4">4</option>
            <option value="5">5</option>
          </select>
        </div>

        <div className="flex flex-row items-center mb-4">
          <label className="text-gray-700 text-sm">Connections:</label>
          <input type="number" value={connections} onChange={handleConnectionsChange} className="w-20 bg-gray-200 appearance-none border-2 border-gray-200 rounded py-2 px-4 text-gray-700 leading-tight focus:outline-none focus:shadow-outline"/>
        </div>
      </div>
    </div>
  );
};

export default App;
